/**
 * ========================================================================================
 * ANIMEVIETSUB (AVS) HLS PLAYLIST DECRYPTION MODULE - v1.3.7
 * ========================================================================================
 *
 * ⚠️ RECONSTRUCTION & MODIFICATION NOTICE:
 * This source code is a DE-OBFUSCATED and RECONSTRUCTED version of the original AVS
 * security module. Functional stability fixes have been applied where de-obfuscation
 * broke implicit dependencies (e.g. explicit stats.parsing initialisation).
 *
 * ═══════════════════════════════════════════════════════════
 * DEOBFUSCATION METHODOLOGY (v1.3.7 Trace)
 * ═══════════════════════════════════════════════════════════
 *
 * Obfuscator: javascript-obfuscator (High Compression)
 *
 * ── Step 1: String Array Recovery ─────────────────────────
 *   Located a0_0x55b0() — 219 encoded entries using a custom base64 alphabet:
 *     "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789+/="
 *   Decoder: a0_0xf29d(index) subtracts a base offset, looks up the encoded
 *   entry, then decodes via decodeURIComponent(percent_encoded_bytes).
 *   Rotation IIFE runs push/shift until checksum target matches:
 *     target = 0xab4b5 + 0x70ce4*2 − 0x1079de = 251571
 *
 * ── Step 2: String Substitution ───────────────────────────
 *   Executed the rotation IIFE + decoder in Node.js (vm.createContext),
 *   iterated indices 0x90–0x1ff to dump the full 219-entry string map.
 *   All _0xXXXXXX(0xYY) call sites replaced with their decoded literals.
 *   Adjacent string concatenations ("foo"+"bar") collapsed inline.
 *
 * ── Step 3: Control Flow Unflattening ─────────────────────
 *   The main IIFE used a _0x25ef9f "guard object" to bundle operators
 *   and dead-branch sentinel strings. Inlined all guard references,
 *   removed dead branches (always-false sentinel comparisons).
 *
 * ── Step 4: Numeric Literal Evaluation ────────────────────
 *   All arithmetic obfuscation evaluated to clean integer literals:
 *     0x14b*0x17 + -0x6f7 + 0x76d*-0x3  →  127   (segment header size)
 *     0x18eb + 0x12b + -0x1997           →  127   (minimum valid byteLength)
 *
 * ═══════════════════════════════════════════════════════════
 * CHANGES FROM v1.3.1
 * ═══════════════════════════════════════════════════════════
 *
 * 1. AvsPlaylistLoader — M3U8 reconstruction logic replaced:
 *    v1.3.1: formatM3U8() rebuilt EXTINF/URL pairs from the raw response.
 *    v1.3.7: Server now returns a complete M3U8 in the decrypted payload.
 *            Instead of rebuilding, the loader now collects all comment lines
 *            that are NOT #EXTINF or #EXT-X-ENDLIST (i.e. the playlist headers
 *            like #EXTM3U, #EXT-X-VERSION, #EXT-X-TARGETDURATION …) and
 *            prepends them to the decrypted content:
 *              response.data = headerLines.join('\n') + '\n' + decrypted
 *            Also added: _c= param detection to guard against unencrypted playlists.
 *
 * 2. AvsEncryptedLoader — now a dedicated segment loader (NEW):
 *    v1.3.1: window.AvsEncryptedLoader === window.AvsPlaylistLoader (same ref).
 *    v1.3.7: Separate loader for TS segments. The CDN prepends a 127-byte
 *            proprietary header to every segment response. This loader strips it
 *            via data.slice(127) before passing data to HLS.js.
 *            Rejects responses with byteLength ≤ 127 as "segment too short".
 *
 * 3. AvsDecryptPlaylist — standalone fetch-based decryptor (NEW):
 *    A top-level async helper that fetches a playlist URL directly
 *    (credentials: 'same-origin'), runs the same decryption pipeline, and
 *    additionally resolves root-relative segment URLs against window.location.origin
 *    (e.g. "/hls/seg001.ts" → "https://animevietsub.id/hls/seg001.ts").
 *    Useful for player integrations that cannot use a custom HLS.js pLoader.
 *
 * 4. Rate-limit handling — added in both loaders (NEW):
 *    On HTTP 429, reads Retry-After header and calls window._avsOnRateLimit(seconds)
 *    instead of propagating a generic error to HLS.js.
 *
 * ═══════════════════════════════════════════════════════════
 * CONFIRMED CRYPTO CHAIN (unchanged from v1.3.1)
 * ═══════════════════════════════════════════════════════════
 *  Step 1  importKey(HMAC-SHA-256, raw, base64url_decode(X-Edge-Tag))
 *  Step 2  sign("${proxyDigest}:${requestTrace}:${cacheNode}") → AES Key Material
 *  Step 3  importKey(AES-GCM, raw, hmac_output_32_bytes)
 *  Step 4  decrypt(AES-GCM, iv=X-Edge-Tag_raw[0..11], ciphertext)
 *           ciphertext = base64url_decode(all _t= token values joined)
 * ═══════════════════════════════════════════════════════════
 */

(function (window) {
  'use strict';

  const isSupported = !!(window.crypto && window.crypto.subtle && window.crypto.subtle.importKey);

  // ─── Helpers ──────────────────────────────────────────────────────────────

  function base64urlToBytes(str) {
    try {
      let s = str.replace(/-/g, '+').replace(/_/g, '/');
      while (s.length % 4) s += '=';
      const bin = atob(s);
      const bytes = new Uint8Array(bin.length);
      for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
      return bytes;
    } catch (e) { return new Uint8Array(); }
  }

  async function avsDecrypt(ciphertext, edgeTag, cacheNode, proxyDigest, requestTrace) {
    const edgeTagBytes = base64urlToBytes(edgeTag);
    const hmacKey = await crypto.subtle.importKey(
      'raw', edgeTagBytes, { name: 'HMAC', hash: 'SHA-256' }, false, ['sign']
    );
    const signInput = new TextEncoder().encode(`${proxyDigest}:${requestTrace}:${cacheNode}`);
    const aesKeyMaterial = await crypto.subtle.sign('HMAC', hmacKey, signInput);
    const aesKey = await crypto.subtle.importKey(
      'raw', aesKeyMaterial, { name: 'AES-GCM' }, false, ['decrypt']
    );
    const iv = edgeTagBytes.slice(0, 12);
    const ciphertextBytes = base64urlToBytes(ciphertext);
    const plaintextBuffer = await crypto.subtle.decrypt({ name: 'AES-GCM', iv }, aesKey, ciphertextBytes);
    return new TextDecoder().decode(plaintextBuffer);
  }

  // ─── AvsPlaylistLoader ────────────────────────────────────────────────────
  //
  // HLS.js-compatible XHR loader for encrypted M3U8 playlists.
  // Usage:  new Hls({ pLoader: window.AvsPlaylistLoader })
  //
  function AvsPlaylistLoader(config) {
    this.stats = {
      trequest: 0, tfirst: 0, tload: 0, loaded: 0, total: 0, retry: 0,
      loading:  { start: 0, first: 0, end: 0 },
      parsing:  { start: 0, end: 0 },
      buffering: { start: 0, first: 0, end: 0 },
    };
    this.context = null;
    this.xhr = null;
  }

  AvsPlaylistLoader.prototype.load = function (context, config, callbacks) {
    this.context = context;
    const xhr = this.xhr = new XMLHttpRequest();
    const stats = this.stats;
    stats.trequest = stats.loading.start = performance.now();
    xhr.open('GET', context.url, true);
    if (context.responseType) xhr.responseType = context.responseType;
    xhr.onreadystatechange = () => {
      if (xhr.readyState === 2) stats.tfirst = stats.loading.first = performance.now();
    };
    xhr.onload = () => {
      stats.tload = stats.loading.end = performance.now();

      // Rate-limit: intercept 429 before HLS.js sees it
      if (xhr.status === 429) {
        let retryAfter = 0;
        try { retryAfter = parseInt(xhr.getResponseHeader('Retry-After') || '0') || 0; } catch (e) {}
        window._avsOnRateLimit && window._avsOnRateLimit(retryAfter);
        return;
      }

      const data = xhr.response || xhr.responseText;
      stats.loaded = stats.total = (data.byteLength !== undefined ? data.byteLength : data.length);
      const response = { url: xhr.responseURL, data };

      if (context.type === 'manifest' && xhr.getResponseHeader('X-Edge-Tag')) {
        const edgeTag     = xhr.getResponseHeader('X-Edge-Tag');
        const cacheNode   = xhr.getResponseHeader('X-Cache-Node');
        const reqTrace    = xhr.getResponseHeader('X-Request-Trace') || '0';
        const proxyDigest = decodeURIComponent(xhr.getResponseHeader('X-Proxy-Digest') || 'anon');
        const rawText     = typeof data === 'string' ? data : new TextDecoder().decode(data);
        const lines       = rawText.split('\n');

        // Detect encrypted mode: first non-comment URL line has a _c= param
        let isEncrypted = false;
        for (let i = 0; i < lines.length; i++) {
          const line = lines[i];
          if (!line.startsWith('#') && line.trim() !== '') {
            if (line.match(/[?&]_c=[0-9]+/)) isEncrypted = true;
            break;
          }
        }

        if (isEncrypted && cacheNode) {
          // Collect M3U8 header lines (all comments except #EXTINF / #EXT-X-ENDLIST)
          // and extract _t= tokens from segment URL lines
          const headerLines = [];
          const tTokens    = [];
          lines.forEach(line => {
            if (line.startsWith('#') || line.trim() === '') {
              if (!line.match(/^#EXTINF:/) && !line.match(/^#EXT-X-ENDLIST/))
                headerLines.push(line);
            } else {
              const m = line.match(/[?&]_t=([^&\s]+)/);
              if (m) tTokens.push(m[1]);
            }
          });

          const ciphertext = tTokens.join('');
          if (ciphertext) {
            avsDecrypt(ciphertext, edgeTag, cacheNode, proxyDigest, reqTrace)
              .then(decrypted => {
                // v1.3.7: server returns a complete M3U8 in decrypted payload;
                // just prepend the collected header lines.
                response.data = headerLines.join('\n') + '\n' + decrypted;
                stats.loaded = stats.total = response.data.length;
                if (stats.parsing) stats.parsing.start = performance.now();
                callbacks.onSuccess(response, stats, context, xhr);
              })
              .catch(err => callbacks.onError(
                { code: 0, text: 'AVS decrypt failed: ' + err.message }, context, xhr
              ));
            return;
          }
        }
      }

      callbacks.onSuccess(response, stats, context, xhr);
    };
    xhr.onerror = () => callbacks.onError({ code: xhr.status, text: xhr.statusText }, context, xhr);
    xhr.send();
  };

  AvsPlaylistLoader.prototype.abort   = function () { if (this.xhr) this.xhr.abort(); };
  AvsPlaylistLoader.prototype.destroy = function () { this.abort(); this.xhr = null; };

  // ─── AvsEncryptedLoader ───────────────────────────────────────────────────
  //
  // HLS.js-compatible XHR loader for AVS-encrypted TS segments.
  // Usage:  new Hls({ fLoader: window.AvsEncryptedLoader })
  //
  // The CDN prepends a 127-byte proprietary header to each segment.
  // This loader always requests arraybuffer, validates size, strips the header.
  //
  function AvsEncryptedLoader(config) {
    this.stats = {
      trequest: 0, tfirst: 0, tload: 0, loaded: 0, total: 0, retry: 0,
      loading:  { start: 0, first: 0, end: 0 },
      parsing:  { start: 0, end: 0 },
      buffering: { start: 0, first: 0, end: 0 },
    };
    this.context = null;
    this.xhr = null;
  }

  AvsEncryptedLoader.prototype.load = function (context, config, callbacks) {
    this.context = context;
    const xhr = this.xhr = new XMLHttpRequest();
    const stats = this.stats;
    stats.trequest = stats.loading.start = performance.now();
    xhr.open('GET', context.url, true);
    xhr.responseType = 'arraybuffer'; // segments are always binary
    xhr.onreadystatechange = () => {
      if (xhr.readyState === 2) stats.tfirst = stats.loading.first = performance.now();
    };
    xhr.onload = () => {
      stats.tload = stats.loading.end = performance.now();

      // Rate-limit: intercept 429 before HLS.js sees it
      if (xhr.status === 429) {
        let retryAfter = 0;
        try { retryAfter = parseInt(xhr.getResponseHeader('Retry-After') || '0') || 0; } catch (e) {}
        window._avsOnRateLimit && window._avsOnRateLimit(retryAfter);
        return;
      }

      const data = xhr.response; // ArrayBuffer
      const response = { url: xhr.responseURL, data };

      // Reject responses too small to contain the 127-byte proprietary header
      if (data.byteLength <= 127) {
        return callbacks.onError({ code: 0, text: 'AVS: segment too short' }, context, xhr);
      }

      // Strip the 127-byte proprietary header prepended by the CDN
      response.data = data.slice(127);
      stats.loaded = stats.total = response.data.byteLength;
      callbacks.onSuccess(response, stats, context, xhr);
    };
    xhr.onerror = () => callbacks.onError({ code: xhr.status, text: xhr.statusText }, context, xhr);
    xhr.send();
  };

  AvsEncryptedLoader.prototype.abort   = function () { if (this.xhr) this.xhr.abort(); };
  AvsEncryptedLoader.prototype.destroy = function () { this.abort(); this.xhr = null; };

  // ─── AvsDecryptPlaylist ───────────────────────────────────────────────────
  //
  // Standalone async helper: fetches and decrypts an AVS playlist URL.
  // Useful for player integrations that cannot use a custom HLS.js pLoader.
  //
  // Usage:
  //   const m3u8 = await window.AvsDecryptPlaylist(url);
  //   // feed m3u8 to player via Blob URL or directly
  //
  // Root-relative segment paths in the decrypted output are resolved to
  // absolute URLs using window.location.origin so the player can reach them.
  //
  window.AvsDecryptPlaylist = async function AvsDecryptPlaylist(url) {
    const res = await fetch(url, { credentials: 'same-origin' });
    if (!res.ok) throw new Error('playlist fetch failed: ' + res.status);

    const edgeTag     = res.headers.get('X-Edge-Tag')      || '';
    const cacheNode   = res.headers.get('X-Cache-Node')    || '';
    const reqTrace    = res.headers.get('X-Request-Trace') || '0';
    const proxyDigest = decodeURIComponent(res.headers.get('X-Proxy-Digest') || 'anon');

    const rawText = await res.text();
    const lines   = rawText.split('\n');

    // Detect encrypted mode
    let isEncrypted = false;
    for (let i = 0; i < lines.length; i++) {
      const line = lines[i];
      if (!line.startsWith('#') && line.trim() !== '') {
        if (line.match(/[?&]_c=[0-9]+/)) isEncrypted = true;
        break;
      }
    }

    // Return raw if not encrypted or missing required headers
    if ((!isEncrypted && !edgeTag) || !cacheNode) return rawText;

    const headerLines = [];
    const tTokens    = [];
    lines.forEach(line => {
      if (line.startsWith('#') || line.trim() === '') {
        if (!line.match(/^#EXTINF:/) && !line.match(/^#EXT-X-ENDLIST/))
          headerLines.push(line);
      } else {
        const m = line.match(/[?&]_t=([^&\s]+)/);
        if (m) tTokens.push(m[1]);
      }
    });

    const ciphertext = tTokens.join('');
    if (!ciphertext) return rawText;

    const decrypted = await avsDecrypt(ciphertext, edgeTag, cacheNode, proxyDigest, reqTrace);

    // Resolve root-relative segment URLs against the current origin
    const origin = window.location.origin;
    const resolved = decrypted.split('\n').map(line => {
      if (line.startsWith('#') || line.trim() === '') return line;
      if (line.startsWith('/')) return origin + line;
      return line;
    }).join('\n');

    return headerLines.join('\n') + '\n' + resolved;
  };

  // ─── Exports ──────────────────────────────────────────────────────────────
  window.AvsPlaylistLoader   = AvsPlaylistLoader;
  window.AvsEncryptedLoader  = AvsEncryptedLoader;
  window._avsCryptoSupported = isSupported;

})(window);